import os
import json
import functools
from datetime import timedelta

import redis
from flask import Flask, session, request, redirect, url_for, render_template

# Configuration
REDIS_HOST = 'localhost'
REDIS_PORT = 6379
REDIS_DB = 0
SESSION_EXPIRATION_SECONDS = 3600  # 1 hour
CACHE_EXPIRATION_SECONDS = 300  # 5 minutes

app = Flask(__name__)

# Generate a strong secret key for session management
app.secret_key = os.urandom(24)

# Initialize Redis client
redis_client = redis.StrictRedis(host=REDIS_HOST, port=REDIS_PORT, db=REDIS_DB, decode_responses=True)

# --- Redis Session Management ---

class RedisSession:
    def __init__(self, session_id=None):
        self.session_id = session_id or self._generate_session_id()
        self.data = self._load_session_data()

    def _generate_session_id(self):
        return os.urandom(16).hex()

    def _load_session_data(self):
        session_data_json = redis_client.get(f"session:{self.session_id}")
        if session_data_json:
            return json.loads(session_data_json)
        return {}

    def save(self):
        redis_client.setex(
            f"session:{self.session_id}",
            SESSION_EXPIRATION_SECONDS,
            json.dumps(self.data)
        )

    def delete(self):
        redis_client.delete(f"session:{self.session_id}")

    def __getitem__(self, key):
        return self.data.get(key)

    def __setitem__(self, key, value):
        self.data[key] = value

    def __delitem__(self, key):
        if key in self.data:
            del self.data[key]

    def get(self, key, default=None):
        return self.data.get(key, default)

    def clear(self):
        self.data = {}

@app.before_request
def load_redis_session():
    session_id = request.cookies.get('session_id')
    if session_id:
        app.logger.debug(f"Loading existing session: {session_id}")
        request.redis_session = RedisSession(session_id)
        # Refresh session expiration on every request
        request.redis_session.save()
    else:
        app.logger.debug("Creating new session")
        request.redis_session = RedisSession()

@app.after_request
def save_redis_session(response):
    if hasattr(request, 'redis_session'):
        # Only save if session data was modified or if it's a new session
        if request.redis_session.data or not request.cookies.get('session_id'):
            request.redis_session.save()
            response.set_cookie(
                'session_id',
                request.redis_session.session_id,
                max_age=SESSION_EXPIRATION_SECONDS,
                httponly=True,
                samesite='Lax'
            )
        elif not request.redis_session.data and request.cookies.get('session_id'):
            # If session was cleared, delete the cookie and Redis entry
            request.redis_session.delete()
            response.delete_cookie('session_id')
    return response

# --- Caching Decorator ---

def cached(key_prefix, expiration=CACHE_EXPIRATION_SECONDS):
    def decorator(func):
        @functools.wraps(func)
        def wrapper(*args, **kwargs):
            # Generate a unique cache key based on function name, args, and kwargs
            # For simplicity, we'll use a basic JSON dump of args/kwargs.
            # In a real app, you might want more robust key generation,
            # especially for complex objects or large arguments.
            cache_key_parts = [key_prefix, func.__name__]
            if args:
                cache_key_parts.append(json.dumps(args, sort_keys=True))
            if kwargs:
                cache_key_parts.append(json.dumps(kwargs, sort_keys=True))
            
            cache_key = ":".join(cache_key_parts)
            
            cached_result = redis_client.get(cache_key)
            if cached_result:
                app.logger.debug(f"Cache hit for key: {cache_key}")
                return json.loads(cached_result)

            app.logger.debug(f"Cache miss for key: {cache_key}. Executing function.")
            result = func(*args, **kwargs)
            redis_client.setex(cache_key, expiration, json.dumps(result))
            return result
        return wrapper
    return decorator

# --- Example Usage ---

# Simulate an expensive database query
@cached(key_prefix="expensive_data", expiration=60) # Cache for 60 seconds
def get_expensive_data(user_id):
    app.logger.info(f"Simulating expensive DB query for user_id: {user_id}")
    import time
    time.sleep(2) # Simulate delay
    return {"user_id": user_id, "data": f"This is expensive data for user {user_id}", "timestamp": time.time()}

@app.route('/')
def index():
    user = request.redis_session.get('user')
    message = request.redis_session.get('message')
    
    # Clear message after displaying it once
    if 'message' in request.redis_session.data:
        del request.redis_session['message']

    return render_template('index.html', user=user, message=message)

@app.route('/login', methods=['GET', 'POST'])
def login():
    if request.method == 'POST':
        username = request.form['username']
        password = request.form['password'] # In a real app, hash and verify password
        if username == 'test' and password == 'password':
            request.redis_session['user'] = {'username': username, 'id': 123}
            request.redis_session['message'] = f"Logged in as {username}!"
            app.logger.info(f"User {username} logged in.")
            return redirect(url_for('index'))
        else:
            request.redis_session['message'] = "Invalid credentials."
    return render_template('login.html')

@app.route('/logout')
def logout():
    user = request.redis_session.get('user', {}).get('username', 'guest')
    request.redis_session.clear() # Clears session data
    request.redis_session['message'] = f"Goodbye, {user}! You have been logged out."
    app.logger.info(f"User {user} logged out.")
    return redirect(url_for('index'))

@app.route('/profile')
def profile():
    user = request.redis_session.get('user')
    if not user:
        request.redis_session['message'] = "You need to log in to view your profile."
        return redirect(url_for('login'))
    
    # Use the cached function
    user_id = user['id']
    profile_data = get_expensive_data(user_id) # This will be cached

    return render_template('profile.html', user=user, profile_data=profile_data)

@app.route('/increment_counter')
def increment_counter():
    counter = request.redis_session.get('counter', 0)
    counter += 1
    request.redis_session['counter'] = counter
    request.redis_session['message'] = f"Counter incremented to: {counter}"
    return redirect(url_for('index'))

